const{MongoClient:MongoClient,ObjectId:ObjectId}=require("mongodb"),MONGO_URI=process.env.MONGO_URI;let client;async function getDb(){return client||(client=await MongoClient.connect(MONGO_URI)),client.db("eltri")}const rateLimitMap=new Map;function checkRateLimit(e){const t=Date.now();if(!rateLimitMap.has(e))return rateLimitMap.set(e,{count:1,start:t}),!0;const s=rateLimitMap.get(e);return t-s.start>6e4?(rateLimitMap.set(e,{count:1,start:t}),!0):!(s.count>=10)&&(s.count++,!0)}function sanitize(e){return"string"!=typeof e?"":e.trim().replace(/[<>]/g,"").replace(/javascript:/gi,"").replace(/on\w+=/gi,"").slice(0,500)}async function verifyCaptcha(e){const t=process.env.HCAPTCHA_SECRET,s=await fetch("https://api.hcaptcha.com/siteverify",{method:"POST",headers:{"Content-Type":"application/x-www-form-urlencoded"},body:`secret=${t}&response=${e}`});return(await s.json()).success}module.exports=async function(e,t){if(t.setHeader("Access-Control-Allow-Origin","*"),t.setHeader("Access-Control-Allow-Methods","GET, POST, DELETE"),t.setHeader("Access-Control-Allow-Headers","Content-Type, x-admin-token"),"OPTIONS"===e.method)return t.status(200).end();const s=await getDb();if("POST"===e.method){if(!checkRateLimit(e.headers["x-forwarded-for"]||e.socket?.remoteAddress||"unknown"))return t.status(429).json({error:"Terlalu banyak request! Coba lagi dalam 1 menit."});const{captchaToken:n}=e.body;if(!n)return t.status(400).json({error:"CAPTCHA wajib diselesaikan!"});if(!await verifyCaptcha(n))return t.status(400).json({error:"CAPTCHA tidak valid!"});const a=sanitize(e.body?.name||""),r=sanitize(e.body?.message||"");return a&&r?a.length<2?t.status(400).json({error:"Nama terlalu pendek!"}):r.length<3?t.status(400).json({error:"Pesan terlalu pendek!"}):(await s.collection("messages").insertOne({name:a,message:r,createdAt:new Date}),t.json({success:!0,message:"Pesan berhasil dikirim!"})):t.status(400).json({error:"Nama dan pesan wajib diisi!"})}if(e.headers["x-admin-token"]!==process.env.ADMIN_TOKEN)return t.status(401).json({error:"Unauthorized"});if("GET"===e.method){const e=await s.collection("messages").find().sort({createdAt:-1}).limit(50).toArray();return t.json(e)}if("DELETE"===e.method){const{id:n}=e.query;return n?(await s.collection("messages").deleteOne({_id:new ObjectId(n)}),t.json({success:!0})):t.status(400).json({error:"ID wajib diisi!"})}};